  {"id":1,"teil":1,"audio_text":"Hallo! Ich heiße Marie. Ich komme aus Frankfurt. Ich bin 28 Jahre alt und Lehrerin.","q":"Woher kommt Marie?","opts":["Berlin","Frankfurt","München"],"ans":1},
  {"id":2,"teil":1,"audio_text":"Guten Tag! Der Kurs beginnt um neun Uhr und endet um elf Uhr. Bitte bringen Sie ein Heft und einen Stift mit.","q":"Wann endet der Kurs?","opts":["Um 10 Uhr","Um 11 Uhr","Um 12 Uhr"],"ans":1},
  {"id":3,"teil":1,"audio_text":"Auf dem Anrufbeantworter: Hallo Klaus, hier ist Anna. Ich bin heute leider krank und kann nicht kommen. Bis morgen!","q":"Warum kommt Anna nicht?","opts":["Sie muss arbeiten.","Sie ist krank.","Sie hat keine Zeit."],"ans":1},
