A2_HOEREN = [
  {"id":1,"teil":1,"audio_text":"Und jetzt die Wettervorhersage für morgen, Donnerstag, den 15. März: Im Norden gibt es Regen und Temperaturen um 8 Grad. Im Süden wird es trockener mit bis zu 16 Grad und zeitweise Sonne. Am Wochenende bessert sich das Wetter überall.","q":"Wie wird das Wetter morgen im Süden?","opts":["Regen und kalt","Trocken mit etwas Sonne","Sturm und Wind"],"ans":1},
  {"id":2,"teil":1,"audio_text":"Durchsage im Kaufhaus Karstadt: Liebe Kunden, heute haben wir besondere Angebote in der Elektronikabteilung im 2. Stock! Fernseher bis zu 30% reduziert. Außerdem: Alle Winterjacken sind heute 50% billiger — solange der Vorrat reicht. Vielen Dank für Ihren Besuch!","q":"Wo sind die Angebote für Fernseher?","opts":["Im Erdgeschoss","Im zweiten Stock","Im dritten Stock"],"ans":1},
  {"id":3,"teil":1,"audio_text":"Auf dem Anrufbeantworter: Guten Tag, hier ist das Reisebüro Schmidt. Wir rufen wegen Ihrer Buchung nach Mallorca an. Leider muss der Flug am 20. Juli von 14:30 Uhr auf 17:00 Uhr verschoben werden. Ihr Hotel bleibt gleich. Bitte rufen Sie uns zurück: 030-44455. Vielen Dank.","q":"Was ändert sich bei der Buchung?","opts":["Das Hotel","Die Flugzeit","Das Ziel"],"ans":1},
  {"id":4,"teil":1,"audio_text":"Radio-Interview: 'Frau Keller, Sie arbeiten seit 20 Jahren als Ärztin. Was hat sich verändert?' — 'Sehr viel! Früher gab es kein Internet. Heute suchen Patienten zuerst online nach ihrer Krankheit und kommen dann zu mir. Das ist manchmal schwierig, weil die Informationen nicht immer richtig sind.'","q":"Was sagt die Ärztin über das Internet?","opts":["Es hilft Ärzten sehr.","Patienten finden dort nicht immer richtige Informationen.","Es war früher besser."],"ans":1},
  {"id":5,"teil":1,"audio_text":"Im Reisebüro: 'Ich möchte gerne für 2 Wochen nach Thailand.' — 'Wann möchten Sie fahren?' — 'Im August.' — 'Gut. Möchten Sie ein Hotel oder eher eine Pension?' — 'Ein 4-Sterne-Hotel bitte, am Strand.' — 'Wir haben ein schönes Angebot: 14 Tage alles inklusive für 1.800 Euro pro Person.'","q":"Was für eine Unterkunft sucht der Kunde?","opts":["Eine Pension","Ein 4-Sterne-Hotel am Strand","Eine Ferienwohnung"],"ans":1},
  {"id":6,"teil":1,"audio_text":"Nachrichten: Die Stadt München plant, ab 2026 den öffentlichen Nahverkehr deutlich auszubauen. Drei neue U-Bahn-Linien sollen entstehen. Die Kosten belaufen sich auf 5 Milliarden Euro. Ziel ist es, weniger Autos in der Innenstadt zu haben und die Luftqualität zu verbessern.","q":"Was ist das Ziel des neuen Projekts?","opts":["Mehr Parkplätze bauen","Weniger Autos in der Innenstadt","Neue Autobahnen bauen"],"ans":1},
  {"id":7,"teil":2,"audio_text":"A: Hallo! Ich brauche einen Termin beim Zahnarzt. B: Wann möchten Sie kommen? A: Am liebsten morgen früh. B: Morgen früh ist alles voll. Übermorgen um 9 Uhr wäre noch frei. A: Geht auch 10 Uhr? B: 10 Uhr ist leider auch besetzt. 9 Uhr oder 14 Uhr. A: Dann 14 Uhr. B: Gut, ich notiere: übermorgen um 14 Uhr. Ihr Name? A: Müller, Andrea Müller.","q":"Wann ist der Termin von Frau Müller?","opts":["Morgen um 9 Uhr","Übermorgen um 9 Uhr","Übermorgen um 14 Uhr"],"ans":2},
  {"id":8,"teil":2,"audio_text":"A: Ich suche Arbeit als Köchin. Haben Sie etwas? B: Ja, ein Restaurant in der Altstadt sucht eine Köchin für abends, Dienstag bis Samstag. A: Wie sind die Arbeitszeiten? B: Von 17 bis 23 Uhr. A: Und das Gehalt? B: 2.200 Euro netto. A: Das klingt gut. Wie kann ich mich bewerben? B: Am besten online auf unserer Website.","q":"An welchen Tagen muss man nicht arbeiten?","opts":["Montag und Sonntag","Samstag und Sonntag","Dienstag und Mittwoch"],"ans":0},
  {"id":9,"teil":2,"audio_text":"A: Hast du das neue Café am Marktplatz schon probiert? B: Nein, noch nicht. Wie ist es? A: Der Kaffee ist super, aber die Kuchen sind das Beste! Hausgemacht. B: Klingt toll. Ist es teuer? A: Nein, sehr günstig für die Qualität. Ein Stück Kuchen kostet 2,50 Euro. B: Oh, das ist wirklich günstig. Gehen wir morgen hin? A: Ja, gerne!","q":"Was ist besonders gut im neuen Café?","opts":["Der Kaffee","Die Kuchen","Der Service"],"ans":1},
  {"id":10,"teil":2,"audio_text":"A: Hallo, ich möchte mich für den Yoga-Kurs anmelden. B: Welchen Level? Wir haben Anfänger, Mittel und Fortgeschritten. A: Ich mache seit einem Jahr Yoga. B: Dann empfehle ich Mittelstufe. Der Kurs ist dienstags 19 Uhr. A: Und der Preis? B: 60 Euro für 8 Einheiten. A: Super. Ich nehme es!","q":"Welchen Kurs bucht die Person?","opts":["Anfänger, montags","Mittelstufe, dienstags","Fortgeschritten, freitags"],"ans":1},
  {"id":11,"teil":2,"audio_text":"A: Können Sie mir sagen, wie ich zum Hauptbahnhof komme? B: Mit dem Bus oder der U-Bahn? A: U-Bahn am liebsten. B: Dann nehmen Sie die Linie 3 bis 'Stadtmitte', dann umsteigen in die Linie 1 Richtung Nord, zwei Stationen, dann sind Sie am Hauptbahnhof. A: Und wie lange dauert das? B: Ca. 20 Minuten.","q":"Wie lange dauert die Fahrt?","opts":["10 Minuten","20 Minuten","30 Minuten"],"ans":1},
  {"id":12,"teil":2,"audio_text":"A: Du weißt doch, dass nächstes Wochenende das Stadtteilfest ist? B: Ja! Ich freue mich schon. Gibt es ein Programm? A: Samstags ist Musik und Essen. Sonntags gibt es einen Flohmarkt und Spiele für Kinder. B: Cool! Sollen wir zusammen hingehen? A: Natürlich! Treffen wir uns samstags um 15 Uhr am Brunnen.","q":"Was gibt es am Sonntag beim Fest?","opts":["Musik und Essen","Flohmarkt und Kinderspiele","Feuerwerk"],"ans":1},
  {"id":13,"teil":3,"audio_text":"Sehr geehrte Fahrgäste, wegen einer Störung im Streckennetz fahren die S-Bahnen zwischen Ostbahnhof und Flughafen heute nur im 20-Minuten-Takt. Normalerweise fahren sie alle 10 Minuten. Wir bitten um Ihr Verständnis und hoffen, die Situation bald zu beheben.","q":"Wie oft fahren die S-Bahnen heute?","opts":["Alle 5 Minuten","Alle 10 Minuten","Alle 20 Minuten"],"ans":2},
  {"id":14,"teil":3,"audio_text":"Willkommen beim Kundenservice von TelePlus. Wenn Sie eine neue SIM-Karte möchten, drücken Sie die 1. Bei Fragen zur Rechnung drücken Sie die 2. Wenn Sie Ihren Vertrag kündigen möchten, drücken Sie die 3. Für alle anderen Anliegen bleiben Sie bitte in der Leitung.","q":"Welche Taste drückt man, um eine Rechnung zu besprechen?","opts":["1","2","3"],"ans":1},
  {"id":15,"teil":3,"audio_text":"Liebe Schülerinnen und Schüler, morgen findet kein Unterricht statt! Die Schule bleibt wegen eines Lehrertages geschlossen. Übermorgen beginnt der Unterricht wieder normal um 7:45 Uhr. Bitte informiert eure Eltern! Habt einen schönen freien Tag!","q":"Warum ist die Schule morgen geschlossen?","opts":["Ferien","Lehrertag","Schlechtes Wetter"],"ans":1},
  {"id":16,"teil":1,"audio_text":"Podcast-Ausschnitt: 'Gesundes Essen muss nicht teuer sein. Ich kaufe Obst und Gemüse auf dem Wochenmarkt — das ist viel billiger als im Supermarkt und frischer! Mein Tipp: Gehen Sie gegen Ende des Marktes hin, dann gibt es oft Rabatte.'","q":"Wann soll man zum Markt gehen, um günstig einzukaufen?","opts":["Am frühen Morgen","Am Ende des Marktes","An Werktagen"],"ans":1},
  {"id":17,"teil":1,"audio_text":"In der Apotheke: 'Guten Tag, ich brauche etwas gegen Kopfschmerzen.' — 'Haben Sie Fieber?' — 'Nein, nur Kopfschmerzen seit heute Morgen.' — 'Dann empfehle ich Aspirin oder Paracetamol. Aspirin hat aber manchmal Magenprobleme. Haben Sie einen empfindlichen Magen?' — 'Ja, eher schon.' — 'Dann nehmen Sie lieber Paracetamol.'","q":"Warum empfiehlt die Apothekerin Paracetamol?","opts":["Es ist billiger.","Der Kunde hat einen empfindlichen Magen.","Es wirkt schneller."],"ans":1},
  {"id":18,"teil":1,"audio_text":"Radiomeldung: Ab dem 1. April gelten neue Regeln für das Mülltrennen in München. Bioabfall muss jetzt in die braune Tonne, Plastik in die gelbe. Glas weiterhin in die Glascontainer. Papier wie gewohnt in die blaue Tonne. Wer falsch trennt, muss eine Strafe zahlen.","q":"Wohin kommt Plastik nach den neuen Regeln?","opts":["In die braune Tonne","In die gelbe Tonne","In die blaue Tonne"],"ans":1},
  {"id":19,"teil":2,"audio_text":"A: Entschuldigung, ist dieser Platz frei? B: Nein, tut mir leid, mein Freund kommt gleich. Aber der Platz da drüben ist frei. A: Oh, danke. Ähm, darf ich fragen — was studieren Sie? B: Ich studiere Medizin im 4. Semester. Und Sie? A: Ich studiere Wirtschaft, bin aber gerade im Auslandssemester aus Japan.","q":"Woher kommt Person A?","opts":["Deutschland","Japan","Korea"],"ans":1},
  {"id":20,"teil":2,"audio_text":"A: Darf ich heute früher gehen? Ich muss meinen Sohn vom Kindergarten abholen — meine Frau ist krank. B: Wie früh meinen Sie? A: Etwa eine Stunde früher, also um 16 statt 17 Uhr. B: Ja, das ist in Ordnung. Machen Sie die Aufgabe für Herrn Weber fertig? A: Natürlich, kein Problem. Ich bin morgen früh auch wieder pünktlich. B: Gut, dann ist alles klar.","q":"Warum möchte der Mitarbeiter früher gehen?","opts":["Er ist krank.","Er muss sein Kind abholen.","Er hat einen Arzttermin."],"ans":1},
  {"id":21,"teil":3,"audio_text":"Durchsage im Flughafen: Passagiere des Fluges AZ 456 nach Rom, Abflug 14:30 Uhr, bitte zum Gate B12 kommen. Das Boarding beginnt jetzt. Bitte halten Sie Ihren Boardingpass und Reisepass bereit.","q":"Was sollen die Passagiere mitbringen?","opts":["Gepäck","Boardingpass und Reisepass","Nur den Boardingpass"],"ans":1},
  {"id":22,"teil":3,"audio_text":"Im Museum: Willkommen im Stadtmuseum! Öffnungszeiten: Dienstag bis Sonntag, 10 bis 18 Uhr. Montags geschlossen. Eintritt: Erwachsene 8 Euro, Kinder unter 12 Jahren kostenlos. Jeden ersten Sonntag im Monat freier Eintritt für alle! Audioguides können an der Kasse gemietet werden.","q":"Wann ist der Eintritt für alle kostenlos?","opts":["Jeden Montag","Jeden ersten Sonntag im Monat","An Feiertagen"],"ans":1},
  {"id":23,"teil":3,"audio_text":"Elternabend-Ansage: Liebe Eltern, der Elternabend am Donnerstag muss leider verschoben werden. Neuer Termin: Dienstag, 19. November um 19:30 Uhr in der Aula. Thema: Schulausflug Paris im März. Bitte alle erscheinen — es müssen Formulare unterschrieben werden!","q":"Warum sollen alle Eltern kommen?","opts":["Es gibt Essen.","Formulare müssen unterschrieben werden.","Der Lehrer möchte sie kennenlernen."],"ans":1},
  {"id":24,"teil":1,"audio_text":"Sportnachrichten: Der FC Bayern München hat gestern das Derby gegen Borussia Dortmund mit 3:1 gewonnen. Alle drei Tore machte der neue Stürmer Gonzalez. Es war sein erstes Bundesliga-Spiel. Nach dem Spiel sagte der Trainer: 'Ich bin sehr stolz auf das Team.'","q":"Wie endete das Spiel?","opts":["2:1 für Bayern","3:1 für Bayern","1:1 Unentschieden"],"ans":1},
  {"id":25,"teil":2,"audio_text":"A: Ich suche ein Geburtstagsgeschenk für meine Mutter. Sie wird 60. B: Was für Interessen hat sie? A: Sie liest gerne, kocht gerne und geht gerne wandern. B: Wie wäre ein schönes Kochbuch? Es gibt gerade ein neues von Tim Mälzer. A: Hmm, sie hat schon viele Kochbücher. B: Dann vielleicht Wanderschuhe? Wir haben gerade Angebote. A: Oh ja! Die Idee ist gut. Zeigen Sie mal...","q":"Was kauft der Kunde wahrscheinlich?","opts":["Ein Buch","Wanderschuhe","Einen Wanderstock"],"ans":1},
  {"id":26,"teil":2,"audio_text":"A: Wie war dein Urlaub in der Türkei? B: Traumhaft! Das Meer war wunderschön. Ich bin jeden Tag geschwommen. A: Hast du viel unternommen? B: Ja, ich habe einen Ausflug nach Ephesus gemacht — super interessant. Und natürlich Shopping auf dem Basar! A: Klingt toll. Ich war noch nie in der Türkei. B: Du musst unbedingt hin! Am besten im Mai oder September, wenn es nicht so heiß ist.","q":"Wann empfiehlt Person B, in die Türkei zu fahren?","opts":["Im Juli oder August","Im Mai oder September","Im Winter"],"ans":1},
  {"id":27,"teil":3,"audio_text":"Hallo, hier ist Dr. Hoffmann von der Praxis Sonnenschein. Ich rufe wegen Ihrer Bluttest-Ergebnisse an. Alles ist in Ordnung! Der Cholesterinwert ist etwas hoch — ich empfehle, weniger Fleisch zu essen und mehr Sport zu treiben. Kein Grund zur Sorge. Rufen Sie mich an, wenn Sie Fragen haben.","q":"Was empfiehlt der Arzt?","opts":["Weniger Fleisch und mehr Sport","Medikamente nehmen","Sofort in die Klinik kommen"],"ans":0},
  {"id":28,"teil":3,"audio_text":"Vortrag-Einleitung: Guten Abend, meine Damen und Herren. Ich freue mich, Sie heute hier begrüßen zu dürfen. Mein Vortrag zum Thema 'Klimawandel und was jeder tun kann' dauert etwa 45 Minuten. Danach haben wir 20 Minuten Zeit für Ihre Fragen. Bitte stellen Sie Ihr Handy auf lautlos.","q":"Wie lange dauert der Vortrag?","opts":["30 Minuten","45 Minuten","60 Minuten"],"ans":1},
  {"id":29,"teil":2,"audio_text":"A: Ich möchte ein Konto eröffnen. B: Gerne! Haben Sie schon ein Konto bei uns? A: Nein, das ist mein erstes. B: Dann brauchen wir Ihren Personalausweis und eine Meldebestätigung. A: Die habe ich dabei. B: Gut. Dann füllen wir jetzt das Formular aus. Das dauert ca. 20 Minuten. A: Kein Problem.","q":"Was braucht man, um ein Konto zu eröffnen?","opts":["Reisepass und Wohnadresse","Personalausweis und Meldebestätigung","Nur einen Ausweis"],"ans":1},
  {"id":30,"teil":3,"audio_text":"Hier die Nachrichten: Eine neue Studie zeigt, dass Deutsche im Durchschnitt 4 Stunden täglich ihr Smartphone benutzen. Bei Jugendlichen zwischen 14 und 24 Jahren sind es sogar 6 Stunden. Experten warnen vor negativen Auswirkungen auf Schlaf und soziale Kontakte. Viele Familien diskutieren nun über 'Handy-freie Zeiten'.","q":"Wie lange nutzen Jugendliche ihr Smartphone täglich?","opts":["4 Stunden","5 Stunden","6 Stunden"],"ans":2},
]


